import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"调试升级","description":"","frontmatter":{"title":"调试升级"},"headers":[],"relativePath":"hardware/legacy-evb/debug-upgrade.md","filePath":"hardware/legacy-evb/debug-upgrade.md","lastUpdated":null}'),p={name:"hardware/legacy-evb/debug-upgrade.md"};function o(d,a,l,r,i,u){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h2 id="adb调试" tabindex="-1">ADB调试 <a class="header-anchor" href="#adb调试" aria-label="Permalink to &quot;ADB调试&quot;">​</a></h2><h4 id="usb-adb-调试" tabindex="-1">USB ADB 调试 <a class="header-anchor" href="#usb-adb-调试" aria-label="Permalink to &quot;USB ADB 调试&quot;">​</a></h4><p>评估板上有两个USB口，PWR口负责供电，DEBUG口连接电脑可以调试。调试时PWR口请连接附带的电源适配器供电。</p><h4 id="wifi-adb-调试" tabindex="-1">WIFI ADB 调试 <a class="header-anchor" href="#wifi-adb-调试" aria-label="Permalink to &quot;WIFI ADB 调试&quot;">​</a></h4><p>AIUI开机启动后会开启WIFI ADB功能，这样通过同网络下的电脑不用连USB也能ADB。调试AIUI模块。通过如下步骤：</p><p>① 首先得到AIUI模块的IP，可以通过路由器查询或者IP扫描；</p><p>② <code>adb connect aiui_ip:5555</code> 提示连接成功；</p><p>③ <code>adb devices</code> 即可看到设备。</p><h2 id="音频保存" tabindex="-1">音频保存 <a class="header-anchor" href="#音频保存" aria-label="Permalink to &quot;音频保存&quot;">​</a></h2><p>下面描述的音频保存的位置都是在AIUI模块的内置SD卡上。</p><h4 id="原始音频" tabindex="-1">原始音频 <a class="header-anchor" href="#原始音频" aria-label="Permalink to &quot;原始音频&quot;">​</a></h4><p>原始音频是麦克风阵列采集到的多通道原始数据，通过手机端评估板控制端，扫描连接设备，进入控制端界面后依次点击 调试 -&gt; 保存音频 即可最长保存3min的原始音频。</p><p>原始音频保存在<code>/sdcard/AIUI/audio/raw</code>中，<strong>评估板内置SD卡存储空间有限，请及时清理不需要的原始音频。</strong></p><h4 id="识别音频" tabindex="-1">识别音频 <a class="header-anchor" href="#识别音频" aria-label="Permalink to &quot;识别音频&quot;">​</a></h4><p>识别音频是麦克风阵列算法对原始音频进行降噪处理后的16k 16bit单声道音频，该音频最终会送到云端进行识别。</p><p>修改配置文件：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;log&quot;:{</span></span>
<span class="line"><span>    &quot;debug_log&quot;:&quot;1&quot;,</span></span>
<span class="line"><span>    &quot;save_datalog&quot;:&quot;1&quot;,</span></span>
<span class="line"><span>    &quot;datalog_path&quot;:&quot;&quot;,</span></span>
<span class="line"><span>    &quot;datalog_size&quot;:1024,</span></span>
<span class="line"><span>    &quot;raw_audio_path&quot;:&quot;&quot;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>将<code>save_datalog</code>置为1，即可把每次交互的识别音频保存下来，保存的位置位于/sdcard/AIUI/data/（此路径可以通过datalog_path配置修改）下，每一次唤醒后的交互音频都保存在此目录下wakeXX开始的文件夹下。</p><p>all.pcm是本次唤醒后交互的全部识别音频，audio-x.pcm是经过本地vad切分后的识别音频，audio-x.txt是对应音频的结果信息。</p>`,19)])])}const h=e(p,[["render",o]]);export{b as __pageData,h as default};
